// src/pages/LandingPage.js
import React, { useState } from "react";
import {
  loginUser,
  registerUser,
  loginWithGoogle,
  resetPassword,
} from "../utils/firebase";
import "./LandingPage.css";

const LOGO_PATH = "/assets/images/clario-logo.png";

export default function LandingPage({ navigate }) {
  const [mode, setMode] = useState("login");
  const [loading, setLoading] = useState(false);
  const [googleLoading, setGoogleLoading] = useState(false);
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  // 👇 NEW STATE FOR PASSWORD TOGGLE
  const [showPassword, setShowPassword] = useState(false);

  const [loginForm, setLoginForm] = useState({
    email: "",
    password: "",
    remember: false,
  });

  const [registerForm, setRegisterForm] = useState({
    name: "",
    email: "",
    password: "",
    confirmPassword: "",
  });

  const isLogin = mode === "login";

  const handleLoginChange = (e) => {
    const { name, value, type, checked } = e.target;

    setLoginForm((prev) => ({
      ...prev,
      [name]: type === "checkbox" ? checked : value,
    }));
  };

  const handleRegisterChange = (e) => {
    const { name, value } = e.target;

    setRegisterForm((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const switchMode = (nextMode) => {
    setError("");
    setMessage("");
    setMode(nextMode);
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");
    setMessage("");
    setLoading(true);

    try {
      await loginUser(loginForm.email, loginForm.password, loginForm.remember);
      navigate("dashboard");
    } catch (err) {
      setError(err.message || "Login failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setError("");
    setMessage("");

    if (registerForm.password !== registerForm.confirmPassword) {
      setError("Passwords do not match.");
      return;
    }

    if (registerForm.password.length < 8) {
      setError("Password must be at least 8 characters.");
      return;
    }

    setLoading(true);

    try {
      await registerUser(
        registerForm.name,
        registerForm.email,
        registerForm.password
      );
      navigate("dashboard");
    } catch (err) {
      setError(err.message || "Account creation failed.");
    } finally {
      setLoading(false);
    }
  };

  const handleForgotPassword = async () => {
    setError("");
    setMessage("");

    try {
      await resetPassword(loginForm.email);
      setMessage("Password reset email sent.");
    } catch (err) {
      setError(err.message || "Reset failed.");
    }
  };

  const handleGoogleLogin = async () => {
    setError("");
    setMessage("");
    setGoogleLoading(true);

    try {
      await loginWithGoogle(loginForm.remember);
      navigate("dashboard");
    } catch (err) {
      setError(err.message || "Google login failed.");
    } finally {
      setGoogleLoading(false);
    }
  };

  return (
    <div className="lp-page">
      <div className="lp-shell">
        <section className="lp-left-panel">
          <img className="lp-logo-top" src={LOGO_PATH} alt="CLARIO logo" />

          <div className="lp-left-content">
            <h1>Welcome back! 👋</h1>
            <p>Log in to continue your journey to confident communication.</p>
          </div>
        </section>

        <section className="lp-right-panel">
          <div className="lp-card">
            <div className="lp-form-transition" key={mode}>
              {isLogin ? (
                <>
                  <div className="lp-card-header">
                    <h2>Log in to your account</h2>
                    <p>Enter your credentials to access your dashboard.</p>
                  </div>

                  <form className="lp-form" onSubmit={handleLogin}>
                    <label className="lp-field">
                      <span>Email address</span>
                      <div className="lp-input-wrap">
                        <input
                          type="email"
                          name="email"
                          value={loginForm.email}
                          onChange={handleLoginChange}
                          required
                        />
                      </div>
                    </label>

                    {/* ✅ PASSWORD WITH TOGGLE */}
                    <label className="lp-field">
                      <span>Password</span>
                      <div className="lp-input-wrap password-wrap">
                        <input
                          type={showPassword ? "text" : "password"}
                          name="password"
                          value={loginForm.password}
                          onChange={handleLoginChange}
                          required
                        />

                        <button
                          type="button"
                          className="toggle-password"
                          onClick={() => setShowPassword((prev) => !prev)}
                        >
                          {showPassword ? "Hide" : "Show"}
                        </button>
                      </div>
                    </label>

                    <div className="lp-form-row">
                      <label className="lp-checkbox">
                        <input
                          type="checkbox"
                          name="remember"
                          checked={loginForm.remember}
                          onChange={handleLoginChange}
                        />
                        <span>Remember me</span>
                      </label>

                      <button
                        type="button"
                        className="lp-text-btn"
                        onClick={handleForgotPassword}
                      >
                        Forgot password?
                      </button>
                    </div>

                    {error && <p className="lp-error">{error}</p>}
                    {message && <p className="lp-success">{message}</p>}

                    <button className="lp-submit-btn" disabled={loading}>
                      Log In →
                    </button>

                    <div className="lp-divider">
                      <span />
                      <p>or continue with</p>
                      <span />
                    </div>

                    <button
                      type="button"
                      className="lp-social-btn"
                      onClick={handleGoogleLogin}
                    >
                      Google
                    </button>

                    <p className="lp-switch-text">
                      Don’t have an account?{" "}
                      <button type="button" onClick={() => switchMode("register")}>
                        Register here
                      </button>
                    </p>
                  </form>
                </>
              ) : (
                <>
                  <div className="lp-card-header">
                    <h2>Create your account</h2>
                  </div>
                </>
              )}
            </div>
          </div>
        </section>
      </div>
    </div>
  );
}
